import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

/**
 * Integration tests for the full notification pipeline:
 * EventBus → NotificationService → Adapters (email/sms/webhook) → History
 *
 * These tests wire up the complete stack and verify end-to-end behavior,
 * including preferences checks, multi-channel dispatch, and history logging.
 */

// ── Helpers ────────────────────────────────────────────────────────

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeOrderCreatedEvent(
  user: User = makeUser(),
  order: Order = makeOrder(),
): OrderCreatedEvent {
  return {
    type: 'order:created',
    order,
    user,
    timestamp: new Date(),
  };
}

function makeOrderStatusChangedEvent(
  order: Order = makeOrder({ status: 'confirmed' }),
  previousStatus = 'pending',
  newStatus = 'confirmed',
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order,
    previousStatus,
    newStatus,
    timestamp: new Date(),
  };
}

// ── Test Suite ─────────────────────────────────────────────────────

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let preferencesRepo: PreferencesRepository;
  let logRepo: NotificationLogRepository;
  let emailAdapter: EmailAdapter;
  let smsAdapter: SmsAdapter;
  let webhookAdapter: WebhookAdapter;

  beforeEach(() => {
    // Reset all counters for deterministic IDs
    resetNotificationIdCounter();
    resetLogIdCounter();
    resetPreferencesIdCounter();

    // Fresh database and repositories
    db = new Database();
    preferencesRepo = new PreferencesRepository(db);
    logRepo = new NotificationLogRepository(db);

    // Services
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesService = new PreferencesService(preferencesRepo);
    historyService = new NotificationHistoryService(logRepo);

    // Wire services together
    notificationService.setPreferencesService(preferencesService);
    notificationService.setHistoryService(historyService);

    // Adapters
    emailAdapter = new EmailAdapter();
    smsAdapter = new SmsAdapter();
    webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });

    // Register all adapters
    notificationService.registerAdapter(emailAdapter);
    notificationService.registerAdapter(smsAdapter);
    notificationService.registerAdapter(webhookAdapter);
  });

  // ── Email Channel ───────────────────────────────────────────────

  describe('email channel', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // Email adapter received the message
      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);
      expect(sentEmails[0]?.email.to).toBe('alice@example.com');
      expect(sentEmails[0]?.email.subject).toContain('Order Confirmation');

      // Notification recorded in service
      const notifications = notificationService.getNotifications();
      const emailNotif = notifications.find((n) => n.channel === 'email');
      expect(emailNotif).toBeDefined();
      expect(emailNotif!.type).toBe('order:confirmation');
    });

    it('should skip email when email preferences are disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      const emailNotifs = notificationService
        .getNotifications()
        .filter((n) => n.channel === 'email');
      expect(emailNotifs).toHaveLength(0);
    });

    it('should skip email when notification type is not in subscribed categories', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'immediate',
          subscribedCategories: ['user:welcome'], // not order:confirmation
        },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
    });

    it('should skip email when frequency is none', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'none' },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
    });
  });

  // ── SMS Channel ─────────────────────────────────────────────────

  describe('sms channel', () => {
    it('should deliver SMS notification when SMS preferences are enabled', async () => {
      const user = makeUser({ email: '+12025551234' });
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent(user));

      // SMS adapter received the message
      const sentMessages = smsAdapter.getSentMessages();
      expect(sentMessages).toHaveLength(1);
      expect(sentMessages[0]?.message.to).toBe('+12025551234');
      expect(sentMessages[0]?.message.body).toContain('Widget');
    });

    it('should skip SMS when SMS preferences are not set', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        // No sms preferences → defaults to disabled
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should skip SMS when SMS is explicitly disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should skip SMS when notification type not in subscribed categories', async () => {
      const user = makeUser({ email: '+12025551234' });
      preferencesService.createPreferences({
        userId: 'user-1',
        sms: {
          enabled: true,
          subscribedCategories: ['user:welcome'],
        },
      });

      await eventBus.emit(makeOrderCreatedEvent(user));

      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });
  });

  // ── Webhook Channel ─────────────────────────────────────────────

  describe('webhook channel', () => {
    it('should deliver webhook notification when webhook preferences are enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const sentWebhooks = webhookAdapter.getSentWebhooks();
      expect(sentWebhooks).toHaveLength(1);
      expect(sentWebhooks[0]?.payload.event).toBe('order:confirmation');
      expect(sentWebhooks[0]?.payload.recipient).toBe('alice@example.com');
      expect(sentWebhooks[0]?.url).toBe('https://hooks.example.com/notify');
    });

    it('should skip webhook when webhook preferences are not set', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        // No webhook preferences → defaults to disabled
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should skip webhook when webhook is explicitly disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        webhook: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  // ── History Logging ─────────────────────────────────────────────

  describe('history logging', () => {
    it('should log delivered notifications in history', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.query({ channel: 'email' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[0]?.notificationId).toBe('notif-0001');
    });

    it('should log failed notifications in history', async () => {
      // Use invalid email so email adapter returns failure
      const user = makeUser({ email: 'not-an-email' });
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent(user));

      const logs = historyService.query({ channel: 'email' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBeDefined();
    });

    it('should log notifications across all channels', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const allLogs = historyService.query({});
      expect(allLogs).toHaveLength(2);

      const channels = allLogs.map((l) => l.channel).sort();
      expect(channels).toEqual(['email', 'webhook']);
    });

    it('should record correct delivery status per channel', async () => {
      // Email will succeed (valid email), SMS will fail (email is not a phone number)
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        sms: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.query({ channel: 'email' });
      const smsLogs = historyService.query({ channel: 'sms' });

      expect(emailLogs).toHaveLength(1);
      expect(emailLogs[0]?.status).toBe('delivered');

      expect(smsLogs).toHaveLength(1);
      expect(smsLogs[0]?.status).toBe('failed'); // email address is not a valid phone number
    });

    it('should be queryable by recipient', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order:confirmation');
    });

    it('should be queryable by notification type', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getByType('order:confirmation');
      expect(logs).toHaveLength(1);
    });
  });

  // ── Preferences Enforcement ─────────────────────────────────────

  describe('preferences enforcement', () => {
    it('should only send to channels the user has enabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should send to multiple enabled channels simultaneously', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);
    });

    it('should send no notifications when all channels are disabled', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
        sms: { enabled: false },
        webhook: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(notificationService.getNotificationCount()).toBe(0);
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should respect category-level preferences per channel', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: {
          enabled: true,
          frequency: 'immediate',
          subscribedCategories: ['order:confirmation'],
        },
        webhook: {
          enabled: true,
          subscribedCategories: ['order:status-update'], // NOT order:confirmation
        },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // Email should send (subscribed to order:confirmation)
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      // Webhook should NOT send (only subscribed to order:status-update)
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });
  });

  // ── Notification Ordering ───────────────────────────────────────

  describe('notification ordering', () => {
    it('should deliver notifications in the order events are emitted', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      const order1 = makeOrder({ id: 'order-1' });
      const order2 = makeOrder({ id: 'order-2' });
      const user = makeUser();

      await eventBus.emit(makeOrderCreatedEvent(user, order1));
      await eventBus.emit(makeOrderCreatedEvent(user, order2));

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(2);
      expect(sentEmails[0]?.email.subject).toContain('order-1');
      expect(sentEmails[1]?.email.subject).toContain('order-2');
    });

    it('should assign sequential notification IDs across events', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeOrderCreatedEvent(makeUser(), makeOrder({ id: 'order-2' })));

      const notifications = notificationService.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });

    it('should preserve ordering in history logs', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      await eventBus.emit(makeOrderCreatedEvent(makeUser(), makeOrder({ id: 'order-1' })));
      await eventBus.emit(makeOrderCreatedEvent(makeUser(), makeOrder({ id: 'order-2' })));

      const logs = historyService.query({});
      expect(logs).toHaveLength(2);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[1]?.notificationId).toBe('notif-0002');
    });

    it('should interleave channel notifications in adapter registration order', async () => {
      // Enable email + webhook; each event produces one notification per channel
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const notifications = notificationService.getNotifications();
      // Email adapter registered first, then webhook
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[1]?.channel).toBe('webhook');
    });
  });

  // ── Event-Driven Triggers ───────────────────────────────────────

  describe('event-driven triggers', () => {
    it('should handle order:created events end-to-end', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      const order = makeOrder({
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
        ],
        total: 45,
      });

      await eventBus.emit(makeOrderCreatedEvent(makeUser(), order));

      const sentEmails = emailAdapter.getSentEmails();
      expect(sentEmails).toHaveLength(1);

      // Verify email content includes all items
      const emailBody = sentEmails[0]?.email.body;
      expect(emailBody).toContain('Widget x2');
      expect(emailBody).toContain('Gadget x1');
      expect(emailBody).toContain('$45.00');
    });

    it('should handle order:status-changed events end-to-end', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      const event = makeOrderStatusChangedEvent(
        makeOrder({ userId: 'user-1', status: 'shipped' }),
        'confirmed',
        'shipped',
      );

      await eventBus.emit(event);

      // Notification is created (recipient is userId per current implementation)
      const notifications = notificationService.getNotifications();
      const emailNotifs = notifications.filter((n) => n.channel === 'email');
      expect(emailNotifs).toHaveLength(1);
      expect(emailNotifs[0]?.body).toContain('confirmed');
      expect(emailNotifs[0]?.body).toContain('shipped');
    });

    it('should not trigger notifications for unregistered event types', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
      });

      // user:created is emitted by UserService but NotificationService
      // does not subscribe to it
      await eventBus.emit({
        type: 'user:created',
        user: makeUser(),
        timestamp: new Date(),
      });

      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  // ── Multi-Channel End-to-End ────────────────────────────────────

  describe('multi-channel end-to-end', () => {
    it('should dispatch to email and webhook with correct content per channel', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // Email adapter formats as HTML email
      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.email.html).toContain('Order Confirmation');

      // Webhook adapter formats as JSON payload
      const webhooks = webhookAdapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);
      expect(webhooks[0]?.payload.event).toBe('order:confirmation');
      expect(webhooks[0]?.payload.subject).toContain('Order Confirmation');

      // Both logged in history as delivered
      const logs = historyService.query({});
      expect(logs).toHaveLength(2);
      expect(logs.every((l) => l.status === 'delivered')).toBe(true);
    });

    it('should handle mixed success/failure across channels', async () => {
      // Enable all channels; email will succeed, SMS will fail (invalid phone)
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // Email: delivered (valid email)
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      // SMS: attempted but recipient is an email, not a phone number
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      // Webhook: delivered (any non-empty recipient works)
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(1);

      // History should reflect actual delivery statuses
      const emailLog = historyService.query({ channel: 'email' });
      const smsLog = historyService.query({ channel: 'sms' });
      const webhookLog = historyService.query({ channel: 'webhook' });

      expect(emailLog[0]?.status).toBe('delivered');
      expect(smsLog[0]?.status).toBe('failed');
      expect(webhookLog[0]?.status).toBe('delivered');
    });

    it('should correctly track total notification count across channels', async () => {
      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: true, frequency: 'immediate' },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // One notification per enabled channel
      expect(notificationService.getNotificationCount()).toBe(2);
      expect(historyService.getCount()).toBe(2);
    });
  });

  // ── Backward Compatibility ──────────────────────────────────────

  describe('backward compatibility', () => {
    it('should send email by default when no preferences exist and no preferences service set', async () => {
      // Remove the preferences service to simulate legacy behavior
      const legacyService = new NotificationService(eventBus);
      legacyService.registerAdapter(emailAdapter);
      legacyService.registerAdapter(smsAdapter);

      await eventBus.emit(makeOrderCreatedEvent());

      // Email should be sent (backward compat)
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      // SMS should NOT be sent (no preferences service = email-only)
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });
  });
});

