  const legacyBus = new EventBus();
  const legacyEmailAdapter = new EmailAdapter();
  const legacySmsAdapter = new SmsAdapter();
  const legacyService = new NotificationService(legacyBus);
  legacyService.registerAdapter(legacyEmailAdapter);
  legacyService.registerAdapter(legacySmsAdapter);

