+
+function makeOrder(overrides: Partial<Order> = {}): Order {
+  return {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
+    total: 20,
+    status: 'pending',
+    createdAt: new Date(),
+    updatedAt: new Date(),
+    ...overrides,
+  };
+}
+
+function makeOrderCreatedEvent(
+  user: User = makeUser(),
+  order: Order = makeOrder(),
+): OrderCreatedEvent {
+  return {
+    type: 'order:created',
+    order,
+    user,
+    timestamp: new Date(),
+  };
+}
+
+function makeOrderStatusChangedEvent(
+  order: Order = makeOrder({ status: 'confirmed' }),
+  previousStatus = 'pending',
+  newStatus = 'confirmed',
+): OrderStatusChangedEvent {
+  return {
+    type: 'order:status-changed',
+    order,
+    previousStatus,
+    newStatus,
+    timestamp: new Date(),
+  };
+}
